var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"오호, 이게 그 로터스의 시니어가 만든 장치란 말이지?","JPN":"ほお、これがあのロータスのシニアが作った装置か。","ENG":"Oho, so this is the device made by the Lotus's Senior?","TWN":"哦哦，這就是洛德斯的Senior製作的裝置嗎？"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_23"},{"id":"L3_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"인플로전 리액터? 이거 설마 이터니움 드라이브를 바탕으로 만든 거야?","JPN":"インプロージョン・リアクター？　まさかエタニウムドライブを基に作ったのか？","ENG":"An implosion reactor? Is this based on the Eternium Drive?","TWN":"內爆反應爐？這難不成是以永恆之金引擎為基礎製造的？"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"하, 천재라는 소문이 사실이었군. 이터니움 드라이브를 모사하다니.","JPN":"ははっ、天才っていう噂は本当だったんだな。エタニウムドライブを真似るとは。","ENG":"Ha, the rumor about you being a genius was true. You replicated the Eternium Drive.","TWN":"哈，竟然能模仿永恆之金引擎，妳果然跟傳聞說的一樣是天才。"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"여, 역시! 기계수집가, 당신이라면 알아줄 줄 알았어!","JPN":"さ、さすが！　機械収集家、あなたなら分かってくれると思った！","ENG":"I-I knew it! Machine Collector, I figured you would notice!","TWN":" 我、我就知道！機械收藏家，果然你會看得懂！"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"단번에 선로전환기가 이터니움 드라이브를 참고해서 만들었다는 걸 알아차렸잖아?","JPN":"線路転換器がエタニウムドライブを参考にして作られたものだってこと、一目でわかってくれたのね！","ENG":"You realized right away that the Track Switcher referenced the Eternium Drive, right?","TWN":"你一眼就認出線路轉換器是參考永恆之金引擎製成的吧？"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"저 멍청이들은 내가 백날 설명해 줘도 못 알아먹겠다는 표정이었다고!","JPN":"あのバカたちは、いくら私が説明しても理解できないって顔してたのに！","ENG":"Those idiots looked lost no matter how many times I explained it!","TWN":"就算我解釋一百遍，那些笨蛋也是一臉聽不懂的表情！"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"이런 천재를 이런 망령 들린 도시에 처박아놓고 잡무만 시키고 있었다니…….","JPN":"これほどの天才を、こんな亡霊都市にぶち込んで雑務ばかりやらせていたとは……","ENG":"To lock a genius like this in a ghost-ridden city and dump only chores on her...","TWN":"竟然把我這種天才關在鬧鬼的城市，還只讓我做雜務……"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"공학의 길을 걷는 선배로서, 후배의 처지가 무척 안타깝지 않아?","JPN":"工学の道を歩む先輩としては、後輩のこの境遇を可哀想だとは思わないか？","ENG":"As a senior in engineering, isn't it painful to see a junior stuck like this?","TWN":"身為走在工學路上的前輩，你不覺得後輩的處境很可憐嗎？"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"선배……?","JPN":"先輩……？","ENG":"Senior...?","TWN":"前輩……？"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"인간의 자질구레한 일에는 관심 없다.","JPN":"人間の些細なことに興味はない。","ENG":"I have no interest in human trifles.","TWN":"我對人類那些瑣碎的事沒興趣。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_TOUCH"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_30"},{"id":"L16_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"나의 끝없는 진화에만 관심이 있을 뿐.","JPN":"私が興味を持つのは、己の果てない進化のみだ。","ENG":"I care only for my endless evolution.","TWN":"我只在意自己無止境的進化。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"시니어, 내 <color=#ffd34c>콜로서스 베이스</color>에서 선로전환기 제작을 완료했다.","JPN":"シニア、私の<color=#ffd34c>コロッサスベース</color>で線路転換器の製作を完了した。","ENG":"Senior, we completed the Track Switcher at my <color=#ffd34c>Colossus Base</color>.","TWN":"Senior，我在我的<color=#ffd34c>巨像基地</color>完成線路轉換器了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"코, 콜로서스 베이스라고?","JPN":"コ、コロッサスベース？","ENG":"C-Colossus Base?","TWN":"巨、巨像基地？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"분명 신지아 회장은 알파트릭스의 소유인 것처럼 말했는데?","JPN":"ヒメノ会長は確か、アルファトリックスが所有しているみたいに言っていたけど？","ENG":"President Shin Jia made it sound like Alphatrix owned that.","TWN":"明明沈佳會長說那是阿爾法崔克斯的資產？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"놈들의 오비탈 베이스는 내가 차지했다.","JPN":"やつらのオービタルベースは私がいただいた。","ENG":"I seized their Orbital Base.","TWN":"他們的軌道基地已經被我佔領了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG"},{"id":"L23_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"클리포트 게임에 참전해 너흴 도운 건 그걸 얻기 위함이었으니.","JPN":"クリフォトゲームに参戦してお前らに協力したのは、それを得るためだったからな。","ENG":"I joined the Qliphoth Game and aided you in order to obtain it.","TWN":"我會參加逆卡巴拉遊戲並協助你們，就是為了得到它。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"……스캐빈저의 대장이라고 했지?","JPN":"……スカベンジャーのボス。","ENG":"...You're the leader of Scavengers, right?","TWN":"……你就是清道夫的隊長吧？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"저 잘빠진 직선, 투박한 동체! 육중한 무기!","JPN":"そのまっすぐ伸びたラインに、ごつい胴体、重量感溢れる武器！","ENG":"Those clean straight lines, that rugged body, the heavy weapons!","TWN":"那筆直的線條、厚實的機體！滿載的武裝！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L29_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"하, 한 번만 만져봐도 돼?!","JPN":"い、一回だけ触ってみてもいい？","ENG":"C-can I touch it just once?!","TWN":"能、能不能讓我摸一次？！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L30_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"당신 말은 뒷전인 것 같은데?","JPN":"お前の話は耳に入ってないようだな。","ENG":"She seems to be ignoring what you are saying.","TWN":"她好像完全沒在聽你說話耶？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L34_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그리고 그 목소리 말이야…….","JPN":"あと、その声なんだけど……","ENG":"And that voice...","TWN":"而且這個聲音……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"그럼 이졸데, 이거 하나만 기억해 줄 수 있니?","JPN":"じゃあイゾルデ、これだけは覚えていてくれる？","ENG":"Isolde, could you remember this one thing for me?","TWN":"伊索德，妳能幫我記住一句話嗎？"},"stage":{"bg":"OMEN_LOTUS_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"이 말을 간직하고 있다가, 꼭 세상을 지켜주길 바라.","JPN":"この言葉を忘れないで、世界を守ってね。","ENG":"Hold on to these words and use them to protect the world.","TWN":"希望妳能把它放在心裡，總有一天能守護世界。"},"stage":{"bg":"OMEN_LOTUS_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"혹시…….","JPN":"もしかして……","ENG":"Are you...","TWN":"難道……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"오호……?","JPN":"ほお……？","ENG":"Oho...?","TWN":"喔喔……？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"실례가 안 된다면 코어를 좀 들여다봐도 될까?","JPN":"失礼じゃなければ、コアをちょっと見せてもらってもいいかな？","ENG":"If you don't mind, may I take a look at your core?","TWN":"如果不介意的話，我可以看看核心嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L50_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"아, 그, 기계 입장에선 알몸을 보여주는 것 같으려나?","JPN":"あっ、その……機械からすると裸を見せるようなことなのかな。","ENG":"Ah, from a machine's point of view, would that feel like showing your bare body?","TWN":"啊、這、對機械來說是不是像被看光一樣？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"},"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L2_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"괘, 괜찮아! 내 실력이라면 그런 느낌도 안 나게 감쪽같이 여닫을 수 있으니까!","JPN":"だ、大丈夫！　私の腕なら、そんな思いさせないぐらい綺麗に開閉できるから！","ENG":"I-it is fine! With my skill, I can open and close it so cleanly you won't even feel it!","TWN":"沒、沒關係！以我的實力，可以讓你完全沒有那種害羞的感覺！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L6_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"……안타깝다는 말 취소.","JPN":"……可哀想だという発言は撤回する。","ENG":"...I take back what I said about feeling sorry.","TWN":"……我收回剛剛覺得你很可憐的話。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"선로전환기는 이미 괴물이 넘겨받아 운송을 시작했다.","JPN":"線路転換器はすでに化け物に引き渡され、輸送中だ。","ENG":"The Track Switcher has already been handed to the monster and transport has begun.","TWN":"線路轉換器已經交給怪物接手並開始運送了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"그리고 선로전환기의 설계를 살펴보는 과정에서 문제점을 하나 발견했지.","JPN":"そして線路転換器の設計を確認する過程で、1つ問題点を発見した。","ENG":"Also, while reviewing the Track Switcher design, I found one problem.","TWN":"我在查看線路轉換器的設計時，發現了一個問題。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"무, 문제점이라고?","JPN":"も、問題点？","ENG":"A p-problem?","TWN":"問、問題？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"내 완벽한 설계에 그럼 오점이 존재할 리가 없는데?","JPN":"私の完璧な設計に、そんな汚点なんてあるわけない。","ENG":"There's no way my perfect design has a flaw.","TWN":"在我完美的設計下不可能有缺陷啊？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"너 같은 공학자들이 한 번씩 저지르는 치명적인 실수다.","JPN":"お前のような工学者が一度は必ず犯す、致命的なミスだ。","ENG":"It is the fatal mistake engineers like you make sooner or later.","TWN":"這是你這種工程師偶爾會犯下的致命錯誤。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_STEAM"},{"id":"L15_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"너무나 당연하다고 생각해 자기도 모르고 넘기는 것들 말이다.","JPN":"当たり前すぎると思い込み、見落としてしまう。","ENG":"The things you assume are so obvious that you do not even notice them.","TWN":"因為妳認為太理所當然了，才會自己都沒意識到。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그, 그게 무슨……!","JPN":"そ、それはどういう……！","ENG":"W-what is that supposed to mean...?!","TWN":"那、那到底是什麼……！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"검토는 완벽했어! 여기서 넘어간 게 있을 리가…….","JPN":"検討は完璧だった！　見落としなんてあるわけ……","ENG":"The review was perfect! There can't be anything I missed...","TWN":"我的檢查結果也是完美的！不可能有疏漏……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"선로전환기는 마왕의 차원 도약 좌표를 교란하기 위해 만들어졌다고 들었다.","JPN":"線路転換器は魔王の次元跳躍座標を撹乱するために作られたと聞いた。","ENG":"I hear the Track Switcher is meant to disrupt the Demon Lord's dimension-jumping coordinates.","TWN":"線路轉換器是為了干擾魔王的次元跳躍座標而製成。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_30"},{"id":"L21_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"그리고 마왕의 진격을 지연시키기 위해서는 많은 양의 이터니움이 필요하지.","JPN":"そして、魔王の進撃を遅延させるためには、大量のエタニウムが要る。","ENG":"And to delay the Demon Lord's advance, a large amount of Eternium is needed.","TWN":"為了延緩魔王的推進，就需要大量的永恆之金。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"하지만 이터니움은 임계 질량 이상 모이면 스스로 반응하는 물질.","JPN":"しかしエタニウムは臨界質量を超えると自ら反応しだす物質。","ENG":"But Eternium spontaneously reacts once it exceeds its critical mass.","TWN":"但永恆之金是一旦超過臨界質量，就會自行反應的物質。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"그로 인해 발생하는 문제를 해결할 방법이 있나?","JPN":"それによって発生する問題を解決する方法はあるのか？","ENG":"Do you have a way to solve the problem that this causes?","TWN":"你有方法解決這個問題嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"응? 무, 문제라고?","JPN":"え？　も、問題？","ENG":"Huh? P-problem?","TWN":"嗯？問、問題？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"어… 활성화라면… 그러니까…….","JPN":"え……活性化というと……ええと……","ENG":"Uh... If we're talking about activation... Well...","TWN":"呃……如果是活性化……也就是說……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"으아아아악! 천재인 내가 이딴 실수를?","JPN":"うわああああっ！　天才の私がこんなミスを！？","ENG":"Aaaagh! How could a genius like me make such a blunder?","TWN":"呃啊啊啊！身為天才的我竟然犯下這種失誤？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L32_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"뭐가 문제인지 알아내신 겁니까?","JPN":"何が問題なのか分かったのですか？","ENG":"Have you figured out what the problem is?","TWN":"你……找出問題了嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"아주 간단한 문제야. 이터니움은 한 자리에 많은 양을 수용할 수 없어.","JPN":"簡単なこと。1か所に大量のエタニウムを受容することはできない。","ENG":"It is very simple. You cannot contain a large mass of Eternium in one place.","TWN":"是個很簡單的問題。永恆之金無法在同一處容納過量的能量。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그랬다간 이곳의 차원 계면이 융해되어 버릴 테니까!","JPN":"そんなことをしたら、その場所の次元界面が融解してしまうから！","ENG":"If you do, the dimension surface here will melt.","TWN":"要是發生那種情況，這裡的次元界面會直接被熔解！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"하지만 선로전환기에 필요한 에너지양은 이 공간이 수용할 수 있는 이터니움의 양을 아득히 초과해.","JPN":"でも線路転換器に必要なエネルギーの量は、この空間が受容できるエタニウムの量を遥かに超える。","ENG":"But the energy the Track Switcher needs far exceeds the amount of Eternium this space can contain.","TWN":"但線路轉換器需要的能量遠遠超過這個空間所能容納的永恆之金量能上限。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그, 그러면 어떻게 해야…….","JPN":"じゃ、じゃあどうすれば……","ENG":"Th-then what should we...","TWN":"那、那該怎麼做……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"침착해라, 시니어.","JPN":"落ち着け、シニア。","ENG":"Calm yourself, Senior.","TWN":"冷靜點，Senior。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"나는 그저 대답을 듣고 싶을 뿐이니까.","JPN":"私は返事が聞きたいだけだ。","ENG":"I only wanted your answer.","TWN":"我只是想聽聽你的答案罷了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그래… 침착하자, 이졸데…….","JPN":"そうだよ……落ち着こう、イゾルデ……","ENG":"Right... calm down, Isolde...","TWN":"對……冷靜下來，伊索德……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CLOCK_02"},{"id":"L43_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"너는 동시 사고 능력자야.","JPN":"あなたは同時思考能力を持ってるのよ。","ENG":"You have the ability to multi-think.","TWN":"你可是具備同時思考能力的天才。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"지금부터 대책을 생각한다면 분명 금방 떠올릴 수 있어.","JPN":"今からでも遅くない、きっとすぐ答えを見つけられる。","ENG":"If you start working out countermeasures now, you will come up with one quickly.","TWN":"只要從現在開始想對策，一定很快就能想到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"대부분의 차원 계면 융해 사고는 이터니움을 한 번에 활성화시켜 일어난 경우였어.","JPN":"次元界面融解事故のほとんどは、エタニウムを一気に活性化させたせいで発生したものだった。","ENG":"Most dimension surface meltdown incidents happened when Eternium was activated all at once.","TWN":"大多數的次元界面熔解事故，都是因為一次將永恆之金全數活性化才會發生。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"단계를 거치지 않고 한 번에 활성화했다간 선로전환기를 가동하더라도 의미 없는 짓이 되겠지.","JPN":"ちゃんとしたステップを踏まず、一気に活性化させたら線路転換器を稼働しても意味がない。","ENG":"If you activate it in a single step, running the Track Switcher will be pointless.","TWN":"如果不按照順序、一次性活性化，就算啟動線路轉換器也毫無意義。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"마왕의 눈에는 이 세계가 어디로든 들어갈 수 있는 빈집처럼 보일 테니까.","JPN":"魔王の目には、この世界がどこからでも入れる空き屋のように見えるはずだから。","ENG":"To the Demon Lord, this world would look like an empty house you can enter from anywhere.","TWN":"在魔王的眼裡，這個世界看起來就像隨時都能進出的空房子。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_CLOCK_02"},{"id":"L50_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그렇다면…….","JPN":"だとしたら……","ENG":"Then...","TWN":"那麼……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_SNAP_CLEAR_REVERB"},{"id":"L1_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"출력을 순차적으로 높여 차원 계면의 손실을 최소화해야 해.","JPN":"出力を徐々に上げて、次元界面の損失を最低限に抑える必要がある。","ENG":"We must raise output in stages to minimize the dimension surface loss.","TWN":"就必須逐步提升輸出，將次元界面的損耗降到最低。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"시간은 좀 걸리겠지만 함선의 이터니움 드라이브 운용과 비슷하게…….","JPN":"時間はかかるけど、艦船がエタニウムドライブを運用するように……","ENG":"It will take some time, similar to how a ship ramps up an Eternium Drive...","TWN":"雖然會花上一點時間，但和艦船運行永恆之金引擎營運的方式很類似……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"실전에서 쓰기엔 무리가 있는 방법이다.","JPN":"実戦に取り入れるには無理がある方法だ。","ENG":"That approach is impractical for combat.","TWN":"那種方法在實戰中根本行不通。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"출력을 서서히 올리는 방법은 차원 계면 안정화에 도움은 되겠지.","JPN":"出力を徐々に上げる方法は、確かに次元界面の安定化には役立つだろう。","ENG":"Gradually increasing output would help stabilize the dimension surface.","TWN":"逐步提升輸出確實有助於穩定次元界面。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"하지만 이터니움을 활성화하는 순간, 적 역시 눈치챈다는 건 고려하지 않았나?","JPN":"しかしエタニウムを活性化させた瞬間、敵に気づかれるという点は考慮していないな？","ENG":"But did you consider that the moment you activate Eternium, the enemy will notice?","TWN":"但你沒想到一旦啟動永恆之金，敵人也會立刻察覺嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"너의 호위는 다시 너를 지키며 싸워야 한다는 제약이 있을 것이고,","JPN":"お前の護衛は再びお前を守りながら戦うことになり。","ENG":"Your escort would be forced to defend you again under that constraint,","TWN":"你的護衛勢必又得邊保護你邊戰鬥，"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"결국 너의 죽음과 동시에 선로전환기는 파괴되어 작전은 실패할 것이다.","JPN":"結局お前の死と同時に線路転換器は破壊され、作戦は失敗するだろう。","ENG":"and the Track Switcher would be destroyed along with your death. The operation would fail.","TWN":"最後線路轉換器只會在你死亡的同時跟著被摧毀，作戰自然宣告失敗。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"해, 해보지 않고는 모르는 거잖아?! 어떻게 그렇게 단정 짓고 말하는 거야?","JPN":"や、やってみないと分からないでしょ？　どうして断言できるの？","ENG":"You can't know without trying! How can you be so certain?","TWN":"這、這種事不試試看怎麼會知道？！你怎麼可以這樣斷定？！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"인과율을 계산하지 않고도 알 수 있는 당연한 사실이니까.","JPN":"因果律を計算せずとも分かる、当然の事実だからだ。","ENG":"Because it is obvious even without crunching causality.","TWN":"因為這理所當然到不用計算因果機率也能知道。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"한 번에 높은 출력을 내더라도 차원 계면 손실을 빠르게 수복할 수 있는 시스템이 필요하다.","JPN":"一気に高出力を出しても、損なわれた次元界面を素早く修復できるシステムが必要だ。","ENG":"We need a system that can rapidly restore the dimension surface loss even when output spikes at once.","TWN":"即使一次輸出很高，也需要能快速修復次元界面損耗的系統。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"단계적으로 출력을 높이기엔 시간이 촉박해.","JPN":"段階的に出力を上げる方法は、時間が足りない。","ENG":"There is not enough time to raise output step by step.","TWN":"階段性提升輸出方式的時間很緊迫。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"하, 그러셔?","JPN":"あ、そう？","ENG":"Oh, is that so?","TWN":"哈，是嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그럼 어디 그 잘난 인공지능으로 차원 계면을 어떻게 안정화시킬지 머리 좀 굴려보지 그래?","JPN":"じゃあ、あなたのその偉そうな人工知能で次元界面をどう安定化させればいいか考えてみたら？","ENG":"Then use that vaunted AI brain of yours and figure out how to stabilize the dimension surface.","TWN":"那就來好好想想看，該怎麼用那你那了不起的人工智慧穩定次元界面吧？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"나는 가장 실현 가능성이 높은 방법을 말하고 있는 거라고…….","JPN":"私は実現可能性が最も高い方法を言ってるの……","ENG":"I'm talking about the most feasible method...","TWN":"我說的是最有實行可能性的方案……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"이 이상의 방법들은 그저 이론일 뿐인 방법들이란 말이야!","JPN":"他の方法は全部、机上の空論にすぎないんだから！","ENG":"Anything beyond that is still just theory!","TWN":"其他方法不過都是紙上談兵的理論罷了！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L20_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"로터스의 시니어가 천재라는 소문은 나도 익히 들어 알고 있다.","JPN":"ロータスのシニアが天才だという噂は、以前から聞いている。","ENG":"I have heard the rumors that the Lotus's Senior is a genius.","TWN":"我也聽說洛德斯的Senior是天才。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"분명 그 대답을 내기 전까지 수많은 가능성을 떠올렸을 터.","JPN":"きっと先程の答えを出すまで、幾つもの可能性を思い浮かべたはずだ。","ENG":"No doubt you considered countless possibilities before settling on that answer.","TWN":"你在給出答案前，肯定想過無數種可能性。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"하지만 지나치게 무모하거나, 현실성이 없어 소거한 방법들이겠지.","JPN":"しかし無謀すぎるか、現実性がないため消去していったのだろう。","ENG":"You discarded the ones that were too reckless or unrealistic.","TWN":"但那些太魯莽或根本不切實際的方案，應該全被你排除了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"무모하거나 현실성이 없다는 단어 그대로, 실현할 가능성이 낮은 거니까.","JPN":"無謀すぎるか現実性がない、それは言葉通り実現可能性が低いものだからよ。","ENG":"Exactly. If it's reckless or unrealistic, the chance of success is low.","TWN":"魯莽或不切實際就表示實現可能性很低。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"결국 공학자라면 실현 가능성이 있는 것들을 만들어야 해.","JPN":"結局、工学者なら実現可能性のあるものを作らないといけない。","ENG":"An engineer must build what is actually feasible.","TWN":"工程師最終要打造的是實現有可能性的事。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"공상뿐인 이론은 사람들이 살아가는 데 도움이 되기 힘드니까.","JPN":"空想に過ぎない理論は、みんなが生きていくためには役に立たないから。","ENG":"Purely fanciful theories rarely help people live their lives.","TWN":"空談理論，無法真正幫助人類的生活。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"처음 이면세계가 나타나고, 침식체가 나타났을 때도 사람들은 헛소리일 뿐이라며 일축했다.","JPN":"最初に裏世界が現れ、侵食体が現れた時も、人々は戯言だと一蹴した。","ENG":"When the Counterside first appeared and C.O.s emerged, people dismissed it as nonsense.","TWN":"當初異世界、侵蝕體出現時，人們也說那只是胡說八道而已。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"퓨처 앳 워 프로젝트가 막 시작되었을 때도 사람들은 불평과 불만을 늘어놓았지.","JPN":"フューチャーアットウォープロジェクトが始まったばかりの頃も、人々は不平不満を述べる一方だった。","ENG":"When the Future-at-War project began, people only complained and criticized.","TWN":"天啟兵器計畫剛開始時，人們也充斥著抱怨與不滿。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"하지만 결국 퓨처 앳 워 프로젝트는 학문의 이상향이 되었다.","JPN":"しかし、結局フューチャーアットウォープロジェクトは学問の理想郷となった。","ENG":"Yet in the end, Future-at-War became an academic ideal.","TWN":"但最後天啟兵器計畫成為學術上的烏托邦。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"오리지널 타이탄은 성공적으로 가동하여 지금도 사람들을 수호하기 위해 움직이고 있다.","JPN":"オリジナルタイタンは稼働に成功し、今も人々を守護するために働いている。","ENG":"The original Titan was successfully activated and even now protects people.","TWN":"原型泰坦也成功啟動，至今仍在守護人類。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"로터스의 시니어.","JPN":"ロータスのシニア。","ENG":"Senior of Lotus.","TWN":"洛德斯的Senio。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"세상을 바꾸기 위해선 공상이라 생각했던 것들을 가능성으로 만들어야 한다.","JPN":"世界を変えるためには、空想だと思っていたことを可能性にする必要がある。","ENG":"To change the world, what was called fantasy must be turned into possibilities.","TWN":"妳若想改變世界，就得將想像化為可能。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"공학자는 이론을 현실로 만들어야 한다.","JPN":"工学者は理論を現実にしなければならない。","ENG":"An engineer must turn theory into reality.","TWN":"工程師的職責，就是把理論化為現實。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"다시 생각하고, 답을 도출해라.","JPN":"もう一度考え、答えを導き出せ。","ENG":"Think again and derive your answer.","TWN":"再想一次，得出你的答案。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"<color=#ffd34c>공학자는 이론을 현실로 만드는 사람이야.</color>","JPN":"<color=#ffd34c>工学者は理論を現実にする人。</color>","ENG":"<color=#ffd34c>An engineer turns theory into reality.</color>","TWN":"<color=#ffd34c>工程師，是把理論化為現實的人。</color>"},"stage":{"bg":"OMEN_LOTUS_03","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"난 그러한 변화를 진화라고 명명했다.","JPN":"私はそのような変化を進化と命名した。","ENG":"I named that very change \\"evolution.\\"","TWN":"我稱這種改變為進化。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"인간의 가능성은 불가능해 보이는 것을 가능하게 만듦으로써 진화하는 거다.","JPN":"人間の可能性は、不可能に見えるものを可能にすることによって進化する。","ENG":"Human potential evolves by making the seemingly impossible possible.","TWN":"人類的可能性，正是將不可能化為可能而加以進化。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"자, 네가 한 단계 더 진화할 수 있음을 보여라.","JPN":"さあ、お前が更なる進化を遂げられることを示してみろ。","ENG":"Now, show me you can evolve one step further.","TWN":"來，讓我看看你能否再進化。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"너희 인간이 아직 한계에 도달하지 않았음을 증명해라.","JPN":"お前ら人間はまだ限界に達していないと、証明してみせろ。","ENG":"Prove that humanity has not yet reached its limit.","TWN":"向我證明你們人類還沒有到達極限。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"너에게 필요한 모든 건 <color=#ffd34c>콜로서스 베이스</color>가, 아니…….","JPN":"お前に必要なすべては<color=#ffd34c>コロッサスベース</color>、いや……","ENG":"Everything you need, the <color=#ffd34c>Colossus Base</color> will provide– no...","TWN":"你所需要的一切，<color=#ffd34c>巨像基地</color>，不……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"<color=#ffd34c>내</color>가 제공하겠다.","JPN":"<color=#ffd34c>私</color>が提供する。","ENG":"<color=#ffd34c>I</color> will provide it.","TWN":"由<color=#ffd34c>我</color>來提供。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_32"},{"id":"L5_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"조, 좋아. 당신이 그렇게 말한다면… 듣고 비웃지나 말라고…….","JPN":"だ、だったら……わかった。あなたがそこまでいうなら……でも聞いて笑わないでね……","ENG":"F-fine. Since you put it that way... just do not laugh when you hear it...","TWN":"好、好吧。既然你都這麼說了……只要聽了別嘲笑我就好……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"이터니움의 에너지를 버티지 못해 차원 계면이 녹아내리는 건 중력붕괴 과정으로 블랙홀이 만들어지는 것과 비슷해.","JPN":"エタニウムのエネルギーに耐えきれず次元界面が溶けてしまう現象は、重力崩壊の過程でブラックホールが発生するのと似ている。","ENG":"The way a dimension surface collapses under Eternium load is similar to a gravitational collapse forming a black hole.","TWN":"無法承受永恆之金的能量導致次元界面融化一點，和重力崩塌形成黑洞的過程有些相似。"},"stage":{"bg":"ETERNIUM","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"중력이 시공간에 영향을 주는 것처럼, 이터니움은 시공간, 더 나아가 차원에도 영향을 주거든.","JPN":"重力が時空間に影響するように、エタニウムは時空間はもちろん、次元にも影響を与えるから。","ENG":"Just as gravity affects spacetime, Eternium affects spacetime and even dimensions.","TWN":"就像重力會影響時空一樣，永恆之金也會影響時空，甚至影響到次元。"},"stage":{"bg":"ETERNIUM","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"문제점은 거기서 시작해.","JPN":"問題はここから。","ENG":"That's where the problem begins.","TWN":"問題就出在這裡。"},"stage":{"bg":"ETERNIUM","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"아직 우리의 기술력으로는 활성화시킨 모든 에너지를 원하는 방향으로 쓸 수가 없다는 거야.","JPN":"まだ私たちの技術力じゃ、活性化させたエネルギーをすべて意図した通りに使うことができない。","ENG":"With our current technology we can't direct all activated energy exactly where we want.","TWN":"以我們現有的技術，還無法讓活性化後的所有能量都用在我們期望的地方。"},"stage":{"bg":"ETERNIUM","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"갈 곳 잃은 잔여 에너지들이 시공간과 차원에 영향을 줘서 계면이 녹아내리는 거고.","JPN":"余ったエネルギーは行き場をなくし、時空間と次元に影響して界面を溶かしてしまう。","ENG":"The residual energy with nowhere to go distorts spacetime and dimensions, melting the surface.","TWN":"那些失去用途的剩餘能量會影響時空與次元，讓界面融解。"},"stage":{"bg":"ETERNIUM","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그래서 나는 일종의 차원 보조 역장을 고안해 봤어.","JPN":"そこで、一種の次元補助力場を考案してみたの。","ENG":"So I devised a kind of auxiliary dimensional stasis field.","TWN":"所以我構思了一種次元輔助力場。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"이터니움의 에너지를 온전히 차원 너머에 전달하는 방법이면서, 우리 세계를 보호하는 거지.","JPN":"エタニウムのエネルギーをロスなしで次元の向こうに届ける上に、私たちの世界を守ることもできる。","ENG":"It would transmit Eternium's energy fully beyond our dimension while shielding our world.","TWN":"既能將永恆之金的能量完整傳出次元，又能保護我們的世界。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"이론적으로는 가능해. 다만, 꽤 섬세한 설계가 필수고, 그걸 위한 시스템 설계를 다시 짜야 해.","JPN":"理論的には可能なはずだよ。でも極めて繊細な設計が求められるし、そのためのシステムも設計し直す必要がある。","ENG":"In theory it works, but it needs exceedingly delicate design, and the system architecture must be rebuilt.","TWN":"理論上是可行的。但需要非常精密的設計，還得重做整套系統架構。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그렇게 되면 이터니움 산출 공식을 바꿔야 하는데…… 거기에 시스템 구축을 위한 시간을 다시 계산하면…….","JPN":"でもそうなると、エタニウム算出公式も変更は避けられないし……システム構築にかかる時間も、再計算すると……","ENG":"That means changing the Eternium yield formula... and if we recalculate the build time for the system...","TWN":"那樣就得修改永恆之金的產出公式……再重新計算建置系統所需的時間……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"꼬마 아가씨 이름은 뭐야?","JPN":"お嬢ちゃん、名前はなんて言うの？","ENG":"What is your name?","TWN":"妳叫什麼名字？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"미래에 세상을 바꿀 공학자의 이름 정도는 미리 알고 싶은데.","JPN":"将来世界を変える工学者の名前、今から覚えておきたいな。","ENG":"I would like to know the name of the engineer who will change the world.","TWN":"我想先知道可以改變未來世界工程師的名字。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LOTUS_ADMIN_NPC_GIRL","text":{"KOREA":"이졸데… 이졸데예요.","JPN":"イゾルデ……イゾルデです。","ENG":"Isolde... I'm Isolde.","TWN":"伊索德……我叫伊索德。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"계산할 필요 없다.","JPN":"計算する必要はない。","ENG":"No need to calculate.","TWN":"不用計算了。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"응? 왜?","JPN":"え？　なんで？","ENG":"Huh? Why?","TWN":"嗯？為什麼？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"네 이론이 가능성을 얻은 순간, 이미 실현될 준비를 마쳤으니까.","JPN":"お前の理論が可能性を得た瞬間、すでに実現のための準備は整った。","ENG":"The moment your theory gained viability, preparations for realization were complete.","TWN":"在你的理論有可能性的那一刻，就已經準備好實現了。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"마지막 조각이 온 모양이군.","JPN":"最後のピースが来たようだな。","ENG":"Sounds like the final piece has arrived.","TWN":"看來最後的拼圖已經到位了。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"직접 밖에 나가 확인해 보도록.","JPN":"外に出て自分で確認してみろ。","ENG":"Let us go out and see for ourselves.","TWN":"妳自己出去看看吧。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"나는 격납고 안에서 시스템 구축을 준비하겠다.","JPN":"私は格納庫の中でシステムの構築を準備する。","ENG":"I will begin preparing the system build inside the hangar.","TWN":"我會在機庫內著手準備建置系統。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"EMBER_OMEN_NPC_QM","text":{"KOREA":"이야~ 사막은 진짜 오랜만이네.","JPN":"いや～砂漠はホンマに久しぶりやな。","ENG":"Wow! It's been ages since I've been to a desert.","TWN":" 哎呀～還真是好久沒來沙漠了。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"EMBER_OMEN_NPC_QM","text":{"KOREA":"여기도 썩 좋은 상황은 아닌가 봐요?","JPN":"ここもあんまり芳しい状況やないみたいやけど？","ENG":"Looks like things are not exactly rosy here either, huh?","TWN":"看來這裡的情況也不太妙嘛？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"EMBER_OMEN_NPC_QM","text":{"KOREA":"하긴, 이런 비상 상황에 멀쩡한 데 찾는 게 더 힘들겠지만.","JPN":"ま、こんな非常事態にそんな余裕がある場所なんて、あるわけないか。","ENG":"Then again, finding any place untouched in a crisis like this would be the real miracle.","TWN":"也是啦，在這種緊急情況下要找到沒事的地方才更難吧。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"음? 당신은……?","JPN":"ん？　あなたは……？","ENG":"Hmm? And you are...?","TWN":"嗯？妳是……？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"EMBER_OMEN_NPC_QM","text":{"KOREA":"신경질적인 산발 머리에, 쾡한 눈! 햇빛을 하도 안 봐가꼬 뽀얗게 질린 피부!","JPN":"神経質そうなボサボサのヘアスタイルに生気のない目！　日に当たらなすぎて真っ白な肌！","ENG":"Frizzy, prickly hair, hollow eyes, skin gone pale from never seeing sunlight!","TWN":"看起來很神經質的蓬亂頭髮、凹陷的黑眼圈！因為不見陽光而蒼白的皮膚！"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"EMBER_OMEN_NPC_QM","text":{"KOREA":"그리고 무엇보다, 당장이라도 터질라 카는 다이나마이트 보디!","JPN":"何より、ボタンが弾け飛ぶ寸前のダイナマイトボディ！","ENG":"And above all, a killer body that can drop 'em in seconds!","TWN":"重點是感覺隨時會爆炸的火藥桶身材！"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"내가 들은 시니어님 인상착의랑 딱 맞네예!","JPN":"ウチが聞いた説明とまったく同じや！","ENG":"Matches the description I heard of the Senior to a tee!","TWN":"和我聽說的Senior外型描述一模一樣！"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L4_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"반갑습니다. 내는 미리네라 캅니다.","JPN":"はじめまして。ウチはオノデラ・マリや。","ENG":"Pleased to meet you. Name's Mi Rinae.","TWN":"妳好，我叫宓璃奈。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};